#[php_module]
pub fn get_module(module: ModuleBuilder) -> ModuleBuilder {
    module
        .class::<Span>()
        .class::<ProcessResult>()
        .class::<FileMetrics>()
        .class::<StructureItem>()
        .class::<CommentInfo>()
        .class::<DocstringInfo>()
        .class::<DocSection>()
        .class::<ImportInfo>()
        .class::<ExportInfo>()
        .class::<SymbolInfo>()
        .class::<Diagnostic>()
        .class::<CodeChunk>()
        .class::<ChunkContext>()
        .class::<PackConfig>()
        .class::<ProcessConfig>()
        .class::<LanguageRegistry>()
        .class::<ParserManifest>()
        .class::<PlatformBundle>()
        .class::<LanguageInfo>()
        .class::<DownloadManager>()
        .class::<Language>()
        .class::<Parser>()
        .class::<Tree>()
        .class::<TreeSitterLanguagePackApi>()
}
